SELECT A.NIP_HIST_MST_SEQ , A.SWORK_SYSTEM , A.SMENU_NM , A.NIP_HIST_TASK_CD , A.SIP_HIST_TASK_NM -- 이력_TASK_명 , A.NIP_BLOCK_MST_SEQ -- IP블록MST_SEQ , A.NIP_ASSIGN_MST_SEQ -- IP배정MST_SEQ , A.NIP_ALLOC_MST_SEQ , A.NLVL_MST_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD -- 센터/본부_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD -- 노드_CD , A.SSVC_OBJ_NM , A.SASSIGN_LEVEL_CD -- 배정/할당상태 , A.SASSIGN_LEVEL_NM , A.SASSIGN_TYPE_CD -- IPMS_서비스_유형_CD , A.SASSIGN_TYPE_NM , A.SIP_ALLOC_EX_TYPE_CD -- 할당_연동_유형_CD , A.SIP_ALLOC_EX_TYPE_NM -- 할당_연동_유형_명 , A.NIPMS_SVC_SEQ -- 상품MST_SEQ , A.SIPMS_SVC_NM -- 상품MST_명 , A.SEX_SVC_CD -- NEOSS_상품코드_CD , A.SSVC_USE_TYPE_CD -- 서비스_이용_목적_CD , A.SSVC_USE_TYPE_NM , A.SIP_CREATE_TYPE_CD -- 생성유형 , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_CD -- IP버전_유형_CD , A.SIP_VERSION_TYPE_NM , A.PIP_PREFIX -- IP_BLOCK_IP형_CIDR , A.SIP_BLOCK -- IP_BLOCK_문자열 , A.NBITMASK -- BITMASK , A.SNETMASK , A.SFIRST_ADDR , A.SLAST_ADDR , A.NFIRST_ADDR , A.NLAST_ADDR , A.SFIRST_IP_PREFERRED , A.SLAST_IP_PREFERRED , A.SFIRST_ADDR_BINARY , A.SLAST_ADDR_BINARY , A.NCNT -- 총IP수 , A.NCLASS_CNT -- CLASS수 , A.SCOMMENT -- 비고 , A.DCREATE_DT -- 등록일자 , A.SCREATE_ID -- 등록자 , A.SCREATE_NM , A.SLLNUM , A.SSUBSCNEALIAS , A.SSUBSCLGIPPORTDESCRIPTION , A.yyyy FROM ( SELECT ROWNUM AS RNUM , A.SWORK_SYSTEM , A.NIP_HIST_MST_SEQ , A.SMENU_NM , A.NIP_HIST_TASK_CD , A.SIP_HIST_TASK_NM -- 이력_TASK_명 , A.NIP_BLOCK_MST_SEQ -- IP블록MST_SEQ , A.NIP_ASSIGN_MST_SEQ -- IP배정MST_SEQ , A.NIP_ALLOC_MST_SEQ , A.NLVL_MST_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD -- 센터/본부_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD -- 노드_CD , A.SSVC_OBJ_NM , A.SASSIGN_LEVEL_CD -- 배정/할당상태 , A.SASSIGN_LEVEL_NM , A.SASSIGN_TYPE_CD -- IPMS_서비스_유형_CD , A.SASSIGN_TYPE_NM , A.SIP_ALLOC_EX_TYPE_CD -- 할당_연동_유형_CD , A.SIP_ALLOC_EX_TYPE_NM -- 할당_연동_유형_명 , A.NIPMS_SVC_SEQ -- 상품MST_SEQ , A.SIPMS_SVC_NM -- 상품MST_명 , A.SEX_SVC_CD -- NEOSS_상품코드_CD , A.SSVC_USE_TYPE_CD -- 서비스_이용_목적_CD , A.SSVC_USE_TYPE_NM , A.SIP_CREATE_TYPE_CD -- 생성유형 , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_CD -- IP버전_유형_CD , A.SIP_VERSION_TYPE_NM , A.PIP_PREFIX -- IP_BLOCK_IP형_CIDR , A.SIP_BLOCK -- IP_BLOCK_문자열 , A.NBITMASK -- BITMASK , A.SNETMASK , A.SFIRST_ADDR , A.SLAST_ADDR , A.NFIRST_ADDR , A.NLAST_ADDR , A.SFIRST_IP_PREFERRED , A.SLAST_IP_PREFERRED , A.SFIRST_ADDR_BINARY , A.SLAST_ADDR_BINARY , A.NCNT -- 총IP수 , A.NCLASS_CNT -- CLASS수 , A.SCOMMENT -- 비고 , A.DCREATE_DT -- 등록일자 , A.SCREATE_ID -- 등록자 , A.SCREATE_NM , A.SLLNUM , A.SSUBSCNEALIAS , A.SSUBSCLGIPPORTDESCRIPTION , A.yyyy FROM ( SELECT A.NIP_HIST_MST_SEQ , (CASE WHEN A.SMENU_NM = 'NeOSS' THEN 'NeOSS' WHEN A.SMENU_NM = 'SDN' THEN 'SDN' ELSE 'IPMS' END) AS SWORK_SYSTEM , A.SMENU_NM , A.NIP_HIST_TASK_CD , B.SIP_HIST_TASK_NM -- 이력_TASK_명 , A.NIP_BLOCK_MST_SEQ -- IP블록MST_SEQ , A.NIP_ASSIGN_MST_SEQ -- IP배정MST_SEQ , A.NIP_ALLOC_MST_SEQ , A.NLVL_MST_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , D.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD -- 센터/본부_CD , E.SLVL_NM AS SSVC_GROUP_NM , A.SSVC_OBJ_CD -- 노드_CD , F.SLVL_NM AS SSVC_OBJ_NM , A.SASSIGN_LEVEL_CD -- 배정/할당상태 , G.SASSIGN_LEVEL_NM , A.SASSIGN_TYPE_CD -- IPMS_서비스_유형_CD , H.SASSIGN_TYPE_NM , A.SIP_ALLOC_EX_TYPE_CD -- 할당_연동_유형_CD , C.SIP_ALLOC_EX_TYPE_NM -- 할당_연동_유형_명 , A.NIPMS_SVC_SEQ -- 상품MST_SEQ , A.SIPMS_SVC_NM -- 상품MST_명 , A.SEX_SVC_CD -- NEOSS_상품코드_CD , A.SSVC_USE_TYPE_CD -- 서비스_이용_목적_CD , I.SSVC_USE_TYPE_NM , A.SIP_CREATE_TYPE_CD -- 생성유형 , J.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_CD -- IP버전_유형_CD , K.SIP_VERSION_TYPE_NM , A.PIP_PREFIX -- IP_BLOCK_IP형_CIDR , A.SIP_BLOCK -- IP_BLOCK_문자열 , A.NBITMASK -- BITMASK , A.SNETMASK , A.SFIRST_ADDR , A.SLAST_ADDR , A.NFIRST_ADDR , A.NLAST_ADDR , A.SFIRST_IP_PREFERRED , A.SLAST_IP_PREFERRED , A.SFIRST_ADDR_BINARY , A.SLAST_ADDR_BINARY , A.NCNT -- 총IP수 , A.NCLASS_CNT -- CLASS수 , A.SCOMMENT -- 비고 , A.DCREATE_DT -- 등록일자 , A.SCREATE_ID -- 등록자 , (CASE WHEN A.SCREATE_ID = 'NeOSS' OR A.SCREATE_ID = 'SDN' THEN A.SCREATE_ID ELSE NVL(NVL(L.SUSER_NM, M.SUSER_NM), A.SCREATE_ID) END) AS SCREATE_NM , DECODE(COUNT(1),1,MAX(A.SLLNUM),0,'',MAX(A.SLLNUM)) AS SLLNUM , DECODE(COUNT(1),1,MAX(A.SSUBSCNEALIAS),0,'','·····') AS SSUBSCNEALIAS , DECODE(COUNT(1),1,MAX(A.SSUBSCLGIPPORTDESCRIPTION),0,'','·····') AS SSUBSCLGIPPORTDESCRIPTION , date_part('year', A.DCREATE_DT) AS yyyy FROM LOG.${tableNm} A LEFT OUTER JOIN LOG.TB_IP_HIST_TASK_CD B ON B.NIP_HIST_TASK_CD = A.NIP_HIST_TASK_CD LEFT OUTER JOIN MST.TB_IP_ALLOC_EX_TYPE_CD C ON C.SIP_ALLOC_EX_TYPE_CD = A.SIP_ALLOC_EX_TYPE_CD LEFT OUTER JOIN MST.TB_SVC_LINE_TYPE_CD D ON D.SSVC_LINE_TYPE_CD = A.SSVC_LINE_TYPE_CD LEFT OUTER JOIN MST.TB_LVL_CD E ON E.SLVL_CD = A.SSVC_GROUP_CD LEFT OUTER JOIN MST.TB_LVL_CD F ON F.SLVL_CD = A.SSVC_OBJ_CD LEFT OUTER JOIN MST.TB_ASSIGN_LEVEL_CD G ON G.SASSIGN_LEVEL_CD = A.SASSIGN_LEVEL_CD LEFT OUTER JOIN MST.TB_ASSIGN_TYPE_CD H ON H.SASSIGN_TYPE_CD = A.SASSIGN_TYPE_CD LEFT OUTER JOIN MST.TB_SVC_USE_TYPE_CD I ON I.SSVC_USE_TYPE_CD = A.SSVC_USE_TYPE_CD LEFT OUTER JOIN MST.TB_IP_CREATE_TYPE_CD J ON J.SIP_CREATE_TYPE_CD = A.SIP_CREATE_TYPE_CD LEFT OUTER JOIN MST.TB_IP_VERSION_TYPE_CD K ON K.SIP_VERSION_TYPE_CD = A.SIP_VERSION_TYPE_CD LEFT OUTER JOIN MST.TB_USER_BAS L ON L.SUSER_ID = A.SCREATE_ID LEFT OUTER JOIN MST.TB_USER_BAS M ON M.SOLD_USER_ID = A.SCREATE_ID WHERE 1=1
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND (A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
)
AND A.SASSIGN_TYPE_CD = #{sassignTypeCd, jdbcType=CHAR}
AND A.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
AND A.SASSIGN_LEVEL_CD = #{sassignLevelCd, jdbcType=CHAR}
AND A.SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}
AND (( A.NFIRST_ADDR >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND A.NLAST_ADDR <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) OR ( A.NFIRST_ADDR <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND A.NLAST_ADDR >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) )
AND A.PIP_PREFIX = #{pipPrefix, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}
AND A.SIP_BLOCK = #{sipBlock, jdbcType=VARCHAR}
AND A.NBITMASK = #{nbitmask, jdbcType=INTEGER}
AND ( A.SSAID ILIKE '%' || #{ssaid, jdbcType=VARCHAR} || '%'
OR A.SORDERNUM ILIKE '%' || #{sordernum, jdbcType=VARCHAR} || '%'
OR A.SLLNUM ILIKE '%' || #{sllnum, jdbcType=VARCHAR} || '%' )
AND A.SLLNUM ILIKE '%' || #{sllnum, jdbcType=VARCHAR} || '%'
AND A.SSAID ILIKE '%' || #{ssaid, jdbcType=VARCHAR} || '%'
AND A.SORDERNUM ILIKE '%' || #{sordernum, jdbcType=VARCHAR} || '%'
AND A.SSUBSCNEALIAS ILIKE '%' || #{ssubscnealiasNe, jdbcType=VARCHAR} || '%'
AND A.SSUBSCLGIPPORTDESCRIPTION ILIKE '%' || #{ssubsclgipportdescription, jdbcType=VARCHAR} || '%'
AND (A.SCREATE_ID ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' OR L.SUSER_ID ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' OR L.SUSER_NM ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' OR M.SUSER_ID ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' OR M.SOLD_USER_ID ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' OR M.SUSER_NM ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' )
AND A.DCREATE_DT BETWEEN #{searchBgnDe, jdbcType=TIMESTAMP} AND #{searchEndDe} || ' 23:59:59'
AND (CASE WHEN A.SMENU_NM = 'NeOSS' THEN 'NeOSS' WHEN A.SMENU_NM = 'SDN' THEN 'SDN' ELSE 'IPMS' END) = #{sworkSystem, jdbcType=VARCHAR}
AND (CASE WHEN A.SMENU_NM = 'NeOSS' THEN 'NeOSS' WHEN A.SMENU_NM = 'SDN' THEN 'SDN' ELSE 'IPMS' END) = #{sworkSystem, jdbcType=VARCHAR}
AND A.NIP_HIST_TASK_CD = #{nipHistTaskCd, jdbcType=BIGINT}
GROUP BY A.NIP_HIST_MST_SEQ , (CASE WHEN A.SMENU_NM = 'NeOSS' THEN 'NeOSS' WHEN A.SMENU_NM = 'SDN' THEN 'SDN' ELSE 'IPMS' END) , A.SMENU_NM , A.NIP_HIST_TASK_CD , B.SIP_HIST_TASK_NM -- 이력_TASK_명 , A.NIP_BLOCK_MST_SEQ -- IP블록MST_SEQ , A.NIP_ASSIGN_MST_SEQ -- IP배정MST_SEQ , A.NIP_ALLOC_MST_SEQ , A.NLVL_MST_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , D.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD -- 센터/본부_CD , E.SLVL_NM , A.SSVC_OBJ_CD -- 노드_CD , F.SLVL_NM , A.SASSIGN_LEVEL_CD -- 배정/할당상태 , G.SASSIGN_LEVEL_NM , A.SASSIGN_TYPE_CD -- IPMS_서비스_유형_CD , H.SASSIGN_TYPE_NM , A.SIP_ALLOC_EX_TYPE_CD -- 할당_연동_유형_CD , C.SIP_ALLOC_EX_TYPE_NM -- 할당_연동_유형_명 , A.NIPMS_SVC_SEQ -- 상품MST_SEQ , A.SIPMS_SVC_NM -- 상품MST_명 , A.SEX_SVC_CD -- NEOSS_상품코드_CD , A.SSVC_USE_TYPE_CD -- 서비스_이용_목적_CD , I.SSVC_USE_TYPE_NM , A.SIP_CREATE_TYPE_CD -- 생성유형 , J.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_CD -- IP버전_유형_CD , K.SIP_VERSION_TYPE_NM , A.PIP_PREFIX -- IP_BLOCK_IP형_CIDR , A.SIP_BLOCK -- IP_BLOCK_문자열 , A.NBITMASK -- BITMASK , A.SNETMASK , A.SFIRST_ADDR , A.SLAST_ADDR , A.NFIRST_ADDR , A.NLAST_ADDR , A.SFIRST_IP_PREFERRED , A.SLAST_IP_PREFERRED , A.SFIRST_ADDR_BINARY , A.SLAST_ADDR_BINARY , A.NCNT -- 총IP수 , A.NCLASS_CNT -- CLASS수 , A.SCOMMENT -- 비고 , A.DCREATE_DT -- 등록일자 , A.SCREATE_ID -- 등록자 , (CASE WHEN A.SCREATE_ID = 'NeOSS' OR A.SCREATE_ID = 'SDN' THEN A.SCREATE_ID ELSE NVL(NVL(L.SUSER_NM, M.SUSER_NM), A.SCREATE_ID) END) ORDER BY A.NIP_HIST_MST_SEQ DESC, A.DCREATE_DT DESC ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE A.RNUM >= #{firstIndex}

SELECT COUNT(*) totalCount FROM ( SELECT A.NIP_HIST_MST_SEQ , (CASE WHEN A.SMENU_NM = 'NeOSS' THEN 'NeOSS' WHEN A.SMENU_NM = 'SDN' THEN 'SDN' ELSE 'IPMS' END) AS SWORK_SYSTEM , A.SMENU_NM , A.NIP_HIST_TASK_CD , B.SIP_HIST_TASK_NM -- 이력_TASK_명 , A.NIP_BLOCK_MST_SEQ -- IP블록MST_SEQ , A.NIP_ASSIGN_MST_SEQ -- IP배정MST_SEQ , A.NIP_ALLOC_MST_SEQ , A.NLVL_MST_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , D.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD -- 센터/본부_CD , E.SLVL_NM AS SSVC_GROUP_NM , A.SSVC_OBJ_CD -- 노드_CD , F.SLVL_NM AS SSVC_OBJ_NM , A.SASSIGN_LEVEL_CD -- 배정/할당상태 , G.SASSIGN_LEVEL_NM , A.SASSIGN_TYPE_CD -- IPMS_서비스_유형_CD , H.SASSIGN_TYPE_NM , A.SIP_ALLOC_EX_TYPE_CD -- 할당_연동_유형_CD , C.SIP_ALLOC_EX_TYPE_NM -- 할당_연동_유형_명 , A.NIPMS_SVC_SEQ -- 상품MST_SEQ , A.SIPMS_SVC_NM -- 상품MST_명 , A.SEX_SVC_CD -- NEOSS_상품코드_CD , A.SSVC_USE_TYPE_CD -- 서비스_이용_목적_CD , I.SSVC_USE_TYPE_NM , A.SIP_CREATE_TYPE_CD -- 생성유형 , J.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_CD -- IP버전_유형_CD , K.SIP_VERSION_TYPE_NM , A.PIP_PREFIX -- IP_BLOCK_IP형_CIDR , A.SIP_BLOCK -- IP_BLOCK_문자열 , A.NBITMASK -- BITMASK , A.SNETMASK , A.SFIRST_ADDR , A.SLAST_ADDR , A.NFIRST_ADDR , A.NLAST_ADDR , A.SFIRST_IP_PREFERRED , A.SLAST_IP_PREFERRED , A.SFIRST_ADDR_BINARY , A.SLAST_ADDR_BINARY , A.NCNT -- 총IP수 , A.NCLASS_CNT -- CLASS수 , A.SCOMMENT -- 비고 , A.DCREATE_DT -- 등록일자 , A.SCREATE_ID -- 등록자 FROM LOG.${tableNm} A LEFT OUTER JOIN LOG.TB_IP_HIST_TASK_CD B ON B.NIP_HIST_TASK_CD = A.NIP_HIST_TASK_CD LEFT OUTER JOIN MST.TB_IP_ALLOC_EX_TYPE_CD C ON C.SIP_ALLOC_EX_TYPE_CD = A.SIP_ALLOC_EX_TYPE_CD LEFT OUTER JOIN MST.TB_SVC_LINE_TYPE_CD D ON D.SSVC_LINE_TYPE_CD = A.SSVC_LINE_TYPE_CD LEFT OUTER JOIN MST.TB_LVL_CD E ON E.SLVL_CD = A.SSVC_GROUP_CD LEFT OUTER JOIN MST.TB_LVL_CD F ON F.SLVL_CD = A.SSVC_OBJ_CD LEFT OUTER JOIN MST.TB_ASSIGN_LEVEL_CD G ON G.SASSIGN_LEVEL_CD = A.SASSIGN_LEVEL_CD LEFT OUTER JOIN MST.TB_ASSIGN_TYPE_CD H ON H.SASSIGN_TYPE_CD = A.SASSIGN_TYPE_CD LEFT OUTER JOIN MST.TB_SVC_USE_TYPE_CD I ON I.SSVC_USE_TYPE_CD = A.SSVC_USE_TYPE_CD LEFT OUTER JOIN MST.TB_IP_CREATE_TYPE_CD J ON J.SIP_CREATE_TYPE_CD = A.SIP_CREATE_TYPE_CD LEFT OUTER JOIN MST.TB_IP_VERSION_TYPE_CD K ON K.SIP_VERSION_TYPE_CD = A.SIP_VERSION_TYPE_CD LEFT OUTER JOIN MST.TB_USER_BAS L ON L.SUSER_ID = A.SCREATE_ID LEFT OUTER JOIN MST.TB_USER_BAS M ON M.SOLD_USER_ID = A.SCREATE_ID WHERE 1=1
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND (A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
)
AND A.SASSIGN_TYPE_CD = #{sassignTypeCd, jdbcType=CHAR}
AND A.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
AND A.SASSIGN_LEVEL_CD = #{sassignLevelCd, jdbcType=CHAR}
AND A.SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}
AND (( A.NFIRST_ADDR >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND A.NLAST_ADDR <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) OR ( A.NFIRST_ADDR <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND A.NLAST_ADDR >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) )
AND A.PIP_PREFIX = #{pipPrefix, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}
AND A.SIP_BLOCK = #{sipBlock, jdbcType=VARCHAR}
AND A.NBITMASK = #{nbitmask, jdbcType=INTEGER}
AND ( A.SSAID ILIKE '%' || #{ssaid, jdbcType=VARCHAR} || '%'
OR A.SORDERNUM ILIKE '%' || #{sordernum, jdbcType=VARCHAR} || '%'
OR A.SLLNUM ILIKE '%' || #{sllnum, jdbcType=VARCHAR} || '%' )
AND A.SLLNUM ILIKE '%' || #{sllnum, jdbcType=VARCHAR} || '%'
AND A.SSAID ILIKE '%' || #{ssaid, jdbcType=VARCHAR} || '%'
AND A.SORDERNUM ILIKE '%' || #{sordernum, jdbcType=VARCHAR} || '%'
AND A.SSUBSCNEALIAS ILIKE '%' || #{ssubscnealiasNe, jdbcType=VARCHAR} || '%'
AND A.SSUBSCLGIPPORTDESCRIPTION = #{ssubsclgipportdescription, jdbcType=VARCHAR}
AND (A.SCREATE_ID ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' OR L.SUSER_ID ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' OR L.SUSER_NM ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' OR M.SUSER_ID ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' OR M.SOLD_USER_ID ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' OR M.SUSER_NM ILIKE '%' || #{screateId, jdbcType=VARCHAR} || '%' )
AND A.DCREATE_DT BETWEEN #{searchBgnDe, jdbcType=TIMESTAMP} AND #{searchEndDe} || ' 23:59:59'
AND (CASE WHEN A.SMENU_NM = 'NeOSS' THEN 'NeOSS' WHEN A.SMENU_NM = 'SDN' THEN 'SDN' ELSE 'IPMS' END) = #{sworkSystem, jdbcType=VARCHAR}
AND A.NIP_HIST_TASK_CD = #{nipHistTaskCd, jdbcType=BIGINT}
GROUP BY A.NIP_HIST_MST_SEQ , (CASE WHEN A.SMENU_NM = 'NeOSS' THEN 'NeOSS' WHEN A.SMENU_NM = 'SDN' THEN 'SDN' ELSE 'IPMS' END) , A.SMENU_NM , A.NIP_HIST_TASK_CD , B.SIP_HIST_TASK_NM -- 이력_TASK_명 , A.NIP_BLOCK_MST_SEQ -- IP블록MST_SEQ , A.NIP_ASSIGN_MST_SEQ -- IP배정MST_SEQ , A.NIP_ALLOC_MST_SEQ , A.NLVL_MST_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , D.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD -- 센터/본부_CD , E.SLVL_NM , A.SSVC_OBJ_CD -- 노드_CD , F.SLVL_NM , A.SASSIGN_LEVEL_CD -- 배정/할당상태 , G.SASSIGN_LEVEL_NM , A.SASSIGN_TYPE_CD -- IPMS_서비스_유형_CD , H.SASSIGN_TYPE_NM , A.SIP_ALLOC_EX_TYPE_CD -- 할당_연동_유형_CD , C.SIP_ALLOC_EX_TYPE_NM -- 할당_연동_유형_명 , A.NIPMS_SVC_SEQ -- 상품MST_SEQ , A.SIPMS_SVC_NM -- 상품MST_명 , A.SEX_SVC_CD -- NEOSS_상품코드_CD , A.SSVC_USE_TYPE_CD -- 서비스_이용_목적_CD , I.SSVC_USE_TYPE_NM , A.SIP_CREATE_TYPE_CD -- 생성유형 , J.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_CD -- IP버전_유형_CD , K.SIP_VERSION_TYPE_NM , A.PIP_PREFIX -- IP_BLOCK_IP형_CIDR , A.SIP_BLOCK -- IP_BLOCK_문자열 , A.NBITMASK -- BITMASK , A.SNETMASK , A.SFIRST_ADDR , A.SLAST_ADDR , A.NFIRST_ADDR , A.NLAST_ADDR , A.SFIRST_IP_PREFERRED , A.SLAST_IP_PREFERRED , A.SFIRST_ADDR_BINARY , A.SLAST_ADDR_BINARY , A.NCNT -- 총IP수 , A.NCLASS_CNT -- CLASS수 , A.SCOMMENT -- 비고 , A.DCREATE_DT -- 등록일자 , A.SCREATE_ID -- 등록자 , (CASE WHEN A.SCREATE_ID = 'NeOSS' OR A.SCREATE_ID = 'SDN' THEN A.SCREATE_ID ELSE NVL(L.SUSER_NM, M.SUSER_NM) END) ) A

mapper.insert:
INSERT INTO LOG.${tableNm}
(
	SMENU_ID
	, SMENU_NM
	, NIP_HIST_TASK_CD
	, NIP_BLOCK_MST_SEQ
	, NIP_ASSIGN_MST_SEQ
	, NIP_ALLOC_MST_SEQ

	, NLVL_MST_SEQ
