, J.SGATEWAYIP , J.SINSTALLADDRESS , J.SINSTALLROADADDRESS , J.SEX_PUSH_YN , J.SODRHOPEDT , J.SODRREGDT , J.SOFFICECODE , J.NIP_LINK_MST_SEQ FROM MST.TB_IP_ASSIGN_MST A LEFT OUTER JOIN MST.TB_SVC_LINE_TYPE_CD B ON B.SSVC_LINE_TYPE_CD = A.SSVC_LINE_TYPE_CD LEFT OUTER JOIN MST.TB_LVL_MST C ON C.NLVL_MST_SEQ = A.NLVL_MST_SEQ LEFT OUTER JOIN MST.TB_LVL_CD D ON D.SLVL_CD = C.SSVC_GROUP_CD LEFT OUTER JOIN MST.TB_LVL_CD E ON E.SLVL_CD = C.SSVC_OBJ_CD LEFT OUTER JOIN MST.TB_IP_VERSION_TYPE_CD F ON F.SIP_VERSION_TYPE_CD = A.SIP_VERSION_TYPE_CD LEFT OUTER JOIN MST.TB_IP_CREATE_TYPE_CD G ON G.SIP_CREATE_TYPE_CD = A.SIP_CREATE_TYPE_CD LEFT OUTER JOIN MST.TB_ASSIGN_TYPE_CD H ON H.SASSIGN_TYPE_CD = A.SASSIGN_TYPE_CD LEFT OUTER JOIN MST.TB_ASSIGN_LEVEL_CD I ON I.SASSIGN_LEVEL_CD = A.SASSIGN_LEVEL_CD LEFT OUTER JOIN MST.TB_IP_ALLOC_MST J ON J.NIP_ASSIGN_MST_SEQ = A.NIP_ASSIGN_MST_SEQ WHERE A.NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT}
